import{_ as e,o as l,c as a,a2 as r}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"北京旅游注意事项","description":"","frontmatter":{},"headers":[],"relativePath":"guide/tips.md","filePath":"guide/tips.md","lastUpdated":1784712887000}'),i={name:"guide/tips.md"};function n(o,t,d,s,h,g){return l(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="北京旅游注意事项" tabindex="-1">北京旅游注意事项 <a class="header-anchor" href="#北京旅游注意事项" aria-label="Permalink to &quot;北京旅游注意事项&quot;">​</a></h1><blockquote><p>&quot;知己知彼，百战不殆。&quot;</p></blockquote><h2 id="行前准备" tabindex="-1">行前准备 <a class="header-anchor" href="#行前准备" aria-label="Permalink to &quot;行前准备&quot;">​</a></h2><h3 id="证件" tabindex="-1">证件 <a class="header-anchor" href="#证件" aria-label="Permalink to &quot;证件&quot;">​</a></h3><p>✅ <strong>身份证</strong>——必带，景区需刷身份证进入 ✅ <strong>学生证</strong>——部分景点半价 ✅ <strong>老年证</strong>——60岁以上优惠</p><p>⚠️ <strong>特别提醒</strong>：</p><ul><li>故宫、国博等必须刷身份证原件</li><li>护照游客需携带护照</li></ul><h3 id="衣物" tabindex="-1">衣物 <a class="header-anchor" href="#衣物" aria-label="Permalink to &quot;衣物&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">季节</th><th style="text-align:left;">必备衣物</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>春秋季</strong></td><td style="text-align:left;">薄外套、长裤、舒适的鞋子</td></tr><tr><td style="text-align:left;"><strong>夏季</strong></td><td style="text-align:left;">短袖、防晒衣、遮阳帽</td></tr><tr><td style="text-align:left;"><strong>冬季</strong></td><td style="text-align:left;">羽绒服、保暖内衣、手套、围巾</td></tr></tbody></table><p>⚠️ <strong>特别提醒</strong>：</p><ul><li>北京景点步行量大，务必穿舒适的鞋子</li><li>故宫、长城等地砖不平，高跟鞋慎穿</li></ul><h3 id="日常用品" tabindex="-1">日常用品 <a class="header-anchor" href="#日常用品" aria-label="Permalink to &quot;日常用品&quot;">​</a></h3><p>✅ 手机充电器/充电宝 ✅ 现金（少量） ✅ 常用药品 ✅ 防晒用品 ✅ 雨具</p><hr><h2 id="交通出行" tabindex="-1">交通出行 <a class="header-anchor" href="#交通出行" aria-label="Permalink to &quot;交通出行&quot;">​</a></h2><h3 id="地铁" tabindex="-1">地铁 <a class="header-anchor" href="#地铁" aria-label="Permalink to &quot;地铁&quot;">​</a></h3><ul><li><strong>运营时间</strong>：5:00-23:00左右</li><li><strong>票价</strong>：3-9元</li><li><strong>支付方式</strong>： <ul><li>亿通行APP（推荐）</li><li>支付宝/微信乘车码</li></ul></li><li><strong>高峰期</strong>：7:30-9:00，17:30-19:00</li></ul><h3 id="出租车-网约车" tabindex="-1">出租车/网约车 <a class="header-anchor" href="#出租车-网约车" aria-label="Permalink to &quot;出租车/网约车&quot;">​</a></h3><ul><li><strong>出租车</strong>：起步价13元</li><li><strong>网约车</strong>：滴滴、美团打车</li></ul><p>⚠️ <strong>自驾不推荐</strong>：</p><ul><li>交通拥堵严重</li><li>停车困难且贵</li><li>外地车限行</li></ul><hr><h2 id="景点预约" tabindex="-1">景点预约 <a class="header-anchor" href="#景点预约" aria-label="Permalink to &quot;景点预约&quot;">​</a></h2><h3 id="必须预约的景点" tabindex="-1">必须预约的景点 <a class="header-anchor" href="#必须预约的景点" aria-label="Permalink to &quot;必须预约的景点&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">预约时间</th><th style="text-align:left;">预约方式</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>故宫</strong></td><td style="text-align:center;">提前7天</td><td style="text-align:left;">官网/微信公众号</td></tr><tr><td style="text-align:left;"><strong>国博</strong></td><td style="text-align:center;">提前7天</td><td style="text-align:left;">官网/微信公众号</td></tr><tr><td style="text-align:left;"><strong>毛主席纪念堂</strong></td><td style="text-align:center;">提前1-6天</td><td style="text-align:left;">微信小程序</td></tr><tr><td style="text-align:left;"><strong>天安门城楼</strong></td><td style="text-align:center;">提前1-7天</td><td style="text-align:left;">官网</td></tr></tbody></table><h3 id="预约攻略" tabindex="-1">预约攻略 <a class="header-anchor" href="#预约攻略" aria-label="Permalink to &quot;预约攻略&quot;">​</a></h3><ol><li><strong>提前预约</strong>：必须提前在官网或微信公众号预约</li><li><strong>实名预约</strong>：需提供身份证信息</li><li><strong>准时抢票</strong>：故宫每晚8点开售</li></ol><hr><h2 id="安全注意" tabindex="-1">安全注意 <a class="header-anchor" href="#安全注意" aria-label="Permalink to &quot;安全注意&quot;">​</a></h2><h3 id="人身安全" tabindex="-1">人身安全 <a class="header-anchor" href="#人身安全" aria-label="Permalink to &quot;人身安全&quot;">​</a></h3><p>✅ 保管好随身物品 ✅ 不要理会陌生人搭讪 ✅ 晚上少走偏僻胡同 ✅ 注意交通安全</p><h3 id="防骗指南" tabindex="-1">防骗指南 <a class="header-anchor" href="#防骗指南" aria-label="Permalink to &quot;防骗指南&quot;">​</a></h3><p>❌ 黑导游——景点周边拉客的不要理会 ❌ 假景点——认准正规门票 ❌ 高价购物——景区周边谨慎消费</p><p>常见骗局：</p><ul><li>&quot;便宜一日游&quot;</li><li>&quot;免费参观&quot;</li><li>&quot;特价门票&quot;</li></ul><hr><h2 id="文明旅游" tabindex="-1">文明旅游 <a class="header-anchor" href="#文明旅游" aria-label="Permalink to &quot;文明旅游&quot;">​</a></h2><h3 id="参观礼仪" tabindex="-1">参观礼仪 <a class="header-anchor" href="#参观礼仪" aria-label="Permalink to &quot;参观礼仪&quot;">​</a></h3><p>✅ 保持安静——博物馆、纪念馆 ✅ 不要触摸展品 ✅ 禁止闪光灯——博物馆 ✅ 排队有序</p><h3 id="宗教场所" tabindex="-1">宗教场所 <a class="header-anchor" href="#宗教场所" aria-label="Permalink to &quot;宗教场所&quot;">​</a></h3><p>✅ 着装得体 ✅ 保持安静 ✅ 尊重信仰</p><hr><h2 id="健康防护" tabindex="-1">健康防护 <a class="header-anchor" href="#健康防护" aria-label="Permalink to &quot;健康防护&quot;">​</a></h2><h3 id="空气质量" tabindex="-1">空气质量 <a class="header-anchor" href="#空气质量" aria-label="Permalink to &quot;空气质量&quot;">​</a></h3><ul><li>关注天气：出发前查看空气质量</li><li>佩戴口罩：AQI&gt;150时</li><li>减少户外：污染严重时</li></ul><h3 id="饮食卫生" tabindex="-1">饮食卫生 <a class="header-anchor" href="#饮食卫生" aria-label="Permalink to &quot;饮食卫生&quot;">​</a></h3><p>✅ 选择正规餐厅 ✅ 不喝生水 ✅ 有问题及时就医</p><h3 id="防暑防寒" tabindex="-1">防暑防寒 <a class="header-anchor" href="#防暑防寒" aria-label="Permalink to &quot;防暑防寒&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">季节</th><th style="text-align:left;">注意</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>夏季</strong></td><td style="text-align:left;">多喝水、避免正午外出</td></tr><tr><td style="text-align:left;"><strong>冬季</strong></td><td style="text-align:left;">保暖、防冻</td></tr></tbody></table><hr><h2 id="紧急联系" tabindex="-1">紧急联系 <a class="header-anchor" href="#紧急联系" aria-label="Permalink to &quot;紧急联系&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">服务</th><th style="text-align:left;">电话</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>报警</strong></td><td style="text-align:left;">110</td></tr><tr><td style="text-align:left;"><strong>急救</strong></td><td style="text-align:left;">120</td></tr><tr><td style="text-align:left;"><strong>火警</strong></td><td style="text-align:left;">119</td></tr><tr><td style="text-align:left;"><strong>旅游投诉</strong></td><td style="text-align:left;">12345</td></tr><tr><td style="text-align:left;"><strong>北京旅游热线</strong></td><td style="text-align:left;">010-12301</td></tr></tbody></table><h3 id="常用医院" tabindex="-1">常用医院 <a class="header-anchor" href="#常用医院" aria-label="Permalink to &quot;常用医院&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">医院</th><th style="text-align:left;">地址</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>协和医院</strong></td><td style="text-align:left;">东城区王府井</td></tr><tr><td style="text-align:left;"><strong>北大医院</strong></td><td style="text-align:left;">西城区西什库</td></tr><tr><td style="text-align:left;"><strong>儿童医院</strong></td><td style="text-align:left;">西城区南礼士路</td></tr></tbody></table><hr><h2 id="省钱攻略" tabindex="-1">省钱攻略 <a class="header-anchor" href="#省钱攻略" aria-label="Permalink to &quot;省钱攻略&quot;">​</a></h2><h3 id="门票优惠" tabindex="-1">门票优惠 <a class="header-anchor" href="#门票优惠" aria-label="Permalink to &quot;门票优惠&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">优惠类型</th><th style="text-align:left;">条件</th><th style="text-align:center;">折扣</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>学生</strong></td><td style="text-align:left;">学生证</td><td style="text-align:center;">半价</td></tr><tr><td style="text-align:left;"><strong>老人</strong></td><td style="text-align:left;">60岁以上</td><td style="text-align:center;">半价或免费</td></tr><tr><td style="text-align:left;"><strong>儿童</strong></td><td style="text-align:left;">1.2米以下</td><td style="text-align:center;">免费</td></tr></tbody></table><h3 id="省钱技巧" tabindex="-1">省钱技巧 <a class="header-anchor" href="#省钱技巧" aria-label="Permalink to &quot;省钱技巧&quot;">​</a></h3><ol><li>办一张公园年票——200元，市属公园通用</li><li>避开节假日——门票、住宿都便宜</li><li>吃小吃——比正餐便宜</li><li>坐地铁——比打车便宜</li></ol><hr><p><strong>💡 Tips</strong>：北京旅游最重要的是提前做好攻略，尤其是故宫、国博等热门景点必须提前预约。</p>',62)])])}const u=e(i,[["render",n]]);export{f as __pageData,u as default};
